#ifdef ENABLE_DP
#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#endif

#ifdef ENABLE_HP
#pragma OPENCL EXTENSION cl_khr_fp16 : enable
#endif

#define COMPUTE_STEP(t, f) ((t) = (t) * (t) + (f))

static inline size_t logical_index(const size_t linear_idx,
                                   const size_t gid,
                                   const size_t lid,
                                   const size_t group_id,
                                   const size_t global_size,
                                   const size_t local_size) {
#ifdef BLOCK_STRIDED
  return group_id * local_size * (size_t)(ELEMENTS_PER_THREAD * FUSION_DEGREE) +
         lid + linear_idx * local_size;
#else
  (void)lid;
  (void)group_id;
  (void)local_size;
  return gid + linear_idx * global_size;
#endif
}

__kernel __attribute__((reqd_work_group_size(blockdim, 1, 1)))
void benchmark_func(const class_T seed, __global class_T* data) {
  const size_t gid = get_global_id(0);
  const size_t lid = get_local_id(0);
  const size_t group_id = get_group_id(0);
  const size_t global_size = get_global_size(0);
  const size_t local_size = get_local_size(0);
  const size_t total_linear = (size_t)(ELEMENTS_PER_THREAD * FUSION_DEGREE);

  const size_t out_idx =
      logical_index(0, gid, lid, group_id, global_size, local_size);

  class_T f0 = data[out_idx];
#if (ELEMENTS_PER_THREAD * FUSION_DEGREE) > 1
  class_T f1 = data[logical_index(1, gid, lid, group_id, global_size, local_size)];
#else
  class_T f1 = f0;
#endif
#if (ELEMENTS_PER_THREAD * FUSION_DEGREE) > 2
  class_T f2 = data[logical_index(2, gid, lid, group_id, global_size, local_size)];
#else
  class_T f2 = f0;
#endif
#if (ELEMENTS_PER_THREAD * FUSION_DEGREE) > 3
  class_T f3 = data[logical_index(3, gid, lid, group_id, global_size, local_size)];
#else
  class_T f3 = f0;
#endif
#if (ELEMENTS_PER_THREAD * FUSION_DEGREE) > 4
  class_T f4 = data[logical_index(4, gid, lid, group_id, global_size, local_size)];
#else
  class_T f4 = f0;
#endif
#if (ELEMENTS_PER_THREAD * FUSION_DEGREE) > 5
  class_T f5 = data[logical_index(5, gid, lid, group_id, global_size, local_size)];
#else
  class_T f5 = f0;
#endif
#if (ELEMENTS_PER_THREAD * FUSION_DEGREE) > 6
  class_T f6 = data[logical_index(6, gid, lid, group_id, global_size, local_size)];
#else
  class_T f6 = f0;
#endif
#if (ELEMENTS_PER_THREAD * FUSION_DEGREE) > 7
  class_T f7 = data[logical_index(7, gid, lid, group_id, global_size, local_size)];
#else
  class_T f7 = f0;
#endif

  f0 = f0 + seed - seed;
  f1 = f1 + seed - seed;
  f2 = f2 + seed - seed;
  f3 = f3 + seed - seed;
  f4 = f4 + seed - seed;
  f5 = f5 + seed - seed;
  f6 = f6 + seed - seed;
  f7 = f7 + seed - seed;

  class_T sum = (class_T)(0);

  for (size_t i = 0; i < total_linear; ++i) {
    const size_t idx = logical_index(i, gid, lid, group_id, global_size, local_size);
    const class_T x = data[idx];

    class_T t0 = x;
    class_T t1 = x;
    class_T t2 = x;
    class_T t3 = x;
    class_T t4 = x;
    class_T t5 = x;
    class_T t6 = x;
    class_T t7 = x;

    for (int j = 0; j < (COMPUTE_ITERATIONS / 8); ++j) {
      COMPUTE_STEP(t0, f0);
      COMPUTE_STEP(t1, f1);
      COMPUTE_STEP(t2, f2);
      COMPUTE_STEP(t3, f3);
      COMPUTE_STEP(t4, f4);
      COMPUTE_STEP(t5, f5);
      COMPUTE_STEP(t6, f6);
      COMPUTE_STEP(t7, f7);
    }

#if (COMPUTE_ITERATIONS % 8) > 0
    COMPUTE_STEP(t0, f0);
#endif
#if (COMPUTE_ITERATIONS % 8) > 1
    COMPUTE_STEP(t1, f1);
#endif
#if (COMPUTE_ITERATIONS % 8) > 2
    COMPUTE_STEP(t2, f2);
#endif
#if (COMPUTE_ITERATIONS % 8) > 3
    COMPUTE_STEP(t3, f3);
#endif
#if (COMPUTE_ITERATIONS % 8) > 4
    COMPUTE_STEP(t4, f4);
#endif
#if (COMPUTE_ITERATIONS % 8) > 5
    COMPUTE_STEP(t5, f5);
#endif
#if (COMPUTE_ITERATIONS % 8) > 6
    COMPUTE_STEP(t6, f6);
#endif
#if (COMPUTE_ITERATIONS % 8) > 7
    COMPUTE_STEP(t7, f7);
#endif

    sum = sum + t0 + t1 + t2 + t3 + t4 + t5 + t6 + t7;
  }

  data[out_idx] = sum;
}
